export const saveProfileData = async (
  userId: string, 
  userType: 'graduating' | 'alumni' | 'student', 
  data: FullProfileData
) => {
  // 1. Create Survey Response (Acts as a snapshot/history record)
  const respondentType = userType === 'graduating' ? 'student' : 'alumni';
  const surveyPayload: any = {
    respondent_type: respondentType,
    submitted_at: new Date().toISOString()
  };

  if (respondentType === 'student') surveyPayload.student_id = userId;
  else surveyPayload.alumni_id = userId;

  const { data: surveyData, error: surveyError } = await supabase
    .from('survey_responses')
    .insert([surveyPayload])
    .select()
    .single();

  if (surveyError) throw surveyError;
  const surveyId = surveyData.id;

  // 2. Insert Education Information (Single Entry)
  if (data.education) {
    // Remove ID if present to avoid conflict on insert
    const { id, ...eduData } = data.education as any; 
    const { error: eduError } = await supabase
      .from('education_information')
      .insert([{ ...eduData, survey_response_id: surveyId }]);
    if (eduError) console.error("Education Save Error", eduError);
  }

  // 3. Insert Employment History (Multiple Entries)
  if (data.employment && data.employment.length > 0) {
    const employmentRecords = data.employment.map(emp => {
        const { id, ...empData } = emp as any;
        return { ...empData, survey_response_id: surveyId };
    });
    const { error: empError } = await supabase
      .from('employment_history')
      .insert(employmentRecords);
    if (empError) console.error("Employment Save Error", empError);
  }

  // 4. Insert Community Engagement (Multiple Entries)
  if (data.community && data.community.length > 0) {
    const validCommunity = data.community.filter(c => c.organization_name).map(com => {
        const { id, ...comData } = com as any;
        return { ...comData, survey_response_id: surveyId };
    });

    if (validCommunity.length > 0) {
        const { error: commError } = await supabase
          .from('community_engagement')
          .insert(validCommunity);
        if (commError) console.error("Community Save Error", commError);
    }
  }

  // 5. Insert Alumni Attributes (Manual Ratings)
  if (data.attributes) {
    const { id, ...attrData } = data.attributes as any;
    const { error: attrError } = await supabase
      .from('alumni_attributes')
      .insert([{ ...attrData, survey_response_id: surveyId }]);
    if (attrError) console.error("Attributes Save Error", attrError);
  }

  return true;
};

import React, { useEffect, useState } from 'react';
import { LogOut, User, BookOpen, Calendar, MapPin, Award, Bell, Search, ChevronDown, Briefcase, LayoutDashboard, Save, Loader2, CheckCircle, Plus, Trash2, Edit2, X, RefreshCw, Building2, ToggleLeft, ToggleRight, Clock, HelpCircle, AlertTriangle, ArrowRight } from 'lucide-react';
import { Student, EmploymentFormState, EmploymentRecord, EmploymentStatus } from '../types';
