                             <div className="space-y-2">
                                <label className="text-xs font-bold text-gray-500 uppercase">Last Company</label>
                                <input required type="text" value={formData.last_company} onChange={e => handleInputChange('last_company', e.target.value)} className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200 focus:border-luGreen outline-none font-semibold text-sm"/>
                            </div>
                        </div>
                    )}

                    {/* Non-Related Reason Section - Shows only if detected */}
                    {isNonRelatedDetected && (
                        <div className="bg-amber-50 p-5 rounded-xl border border-amber-200 animate-fade-in">
                            <div className="flex gap-3 mb-3">
                                <AlertTriangle className="text-amber-500 shrink-0" />
                                <div>
                                    <h5 className="font-bold text-amber-800 text-sm">Course Misalignment Detected</h5>
                                    <p className="text-xs text-amber-700 mt-1">Our system detected that this role might not be aligned with your program ({user.program}). Please specify a reason:</p>
                                </div>
                            </div>
                            <select 
                                required 
                                value={formData.alignment_reason || ''} 
                                onChange={e => handleInputChange('alignment_reason', e.target.value)}
                                className="w-full p-3 bg-white border border-amber-300 rounded-xl text-sm font-semibold text-gray-700 outline-none focus:ring-2 focus:ring-amber-200"
                            >
                                <option value="">Select Reason...</option>
                                <option value="Better Salary/Benefits">Better Salary and Benefits</option>
                                <option value="Career Advancement">Career Advancement Opportunity</option>
                                <option value="No Job Opportunity">No Job Opportunity in Field</option>
                                <option value="Career Shift">Career Shift / Passion</option>
                                <option value="Family Influence">Family Influence</option>
                                <option value="Proximity">Proximity to Residence</option>
                            </select>
                        </div>
                    )}

                    {/* Submit Actions */}
                    <div className="pt-4 flex gap-3">
                        <button type="submit" disabled={submitting} className="flex-1 py-3.5 bg-luGreen text-white font-bold rounded-xl shadow-lg hover:shadow-green-200 hover:-translate-y-0.5 transition-all flex justify-center items-center gap-2">
                            {submitting ? <Loader2 size={18} className="animate-spin"/> : <Save size={18}/>}
                            Save Status
                        </button>
                        <button type="button" onClick={cancelForm} className="px-6 py-3.5 bg-gray-100 text-gray-600 font-bold rounded-xl hover:bg-gray-200 transition-colors">
                            Cancel
                        </button>
                    </div>
                </form>
            )}
        </div>
    </div>
  );
};

export default EmploymentStatusPage;

import React, { useEffect, useState } from 'react';
import { LogOut, User, BookOpen, Calendar, MapPin, Award, Bell, Search, ChevronDown, Briefcase, LayoutDashboard, Save, Loader2, CheckCircle, Plus, Trash2, Edit2, X, RefreshCw, Building2, ToggleLeft, ToggleRight, Clock, HelpCircle, AlertTriangle, ArrowRight, Layers } from 'lucide-react';
import { Student, EmploymentFormState, EmploymentRecord, EmploymentStatus } from '../types';
import { supabase } from '../lib/supabaseClient';
import { analyzeJobDetails } from '../services/employmentAI';

interface EmploymentStatusPageProps {
  user: Student;
}

const EmploymentStatusPage: React.FC<EmploymentStatusPageProps> = ({ user }) => {
  const [submitting, setSubmitting] = useState(false);
  const [loadingRecords, setLoadingRecords] = useState(false);
  const [employmentRecords, setEmploymentRecords] = useState<EmploymentRecord[]>([]);

  // View State
  const [viewMode, setViewMode] = useState<'list' | 'form'>('list');
  const [selectedStatus, setSelectedStatus] = useState<EmploymentStatus | null>(null);
  const [showStatusSelector, setShowStatusSelector] = useState(false);

  // Transition State
  const [showTransitionModal, setShowTransitionModal] = useState(false);
  const [pendingStatus, setPendingStatus] = useState<EmploymentStatus | null>(null);

  // New: Record View Toggle
  const [recordViewType, setRecordViewType] = useState<'Employed' | 'Self-employed'>('Employed');

  // New: Non-Related Detection State
  const [isNonRelatedDetected, setIsNonRelatedDetected] = useState(false);

  // Form State
  const initialFormState: EmploymentFormState = {
    employment_status: '',
    current_position: '',
    date_hired: '',
    company_name: '',
    company_address: '',
    business_name: '',
    business_address: '',
    business_type: '',
    business_contact_no: '',
    unemployed_reasons: '',
    last_company: '',
    retirement_reason: '',
    date_retired: '',
    business_duration: '',
    alignment_reason: ''
  };
  const [formData, setFormData] = useState<EmploymentFormState>(initialFormState);

  // --- Data Fetching ---
  const fetchEmploymentRecords = async () => {
    setLoadingRecords(true);
    try {
        if (!user.id) {
            console.warn("User ID is missing, cannot fetch records.");
            return;
        }

        const idColumn = user.enrollment_status === 'Graduating' ? 'student_id' : 'alumni_id';

        // 1. Get Survey Responses IDs for this user
        const { data: surveys, error: surveyError } = await supabase
            .from('survey_responses')
            .select('id')
            .eq(idColumn, user.id);

        if (surveyError) {
            console.error("Error fetching surveys:", JSON.stringify(surveyError));
            throw new Error(surveyError.message);
        }

        if (!surveys || surveys.length === 0) {
            setEmploymentRecords([]);
            setLoadingRecords(false);
            setShowStatusSelector(true); // Show selector if no records
            return;
        }

        const surveyIds = surveys.map(s => s.id);

        // 2. Get Employment Info linked to those surveys
        const { data: records, error: recordsError } = await supabase
            .from('employment_information')
            .select('*')
            .in('survey_response_id', surveyIds)
            .order('id', { ascending: false }); // Latest first

        if (recordsError) {
             console.error("Error fetching employment info:", JSON.stringify(recordsError));
             throw new Error(recordsError.message);
        }

        const typedRecords = records as EmploymentRecord[];
        setEmploymentRecords(typedRecords);

        // Logic for Initial View State
        if (typedRecords.length > 0) {
            const hasEmployed = typedRecords.some(r => r.employment_status === 'Employed');
            const hasSelfEmployed = typedRecords.some(r => r.employment_status === 'Self-employed');

            // Smartly set view type: 
            // - If user has both, keep current view if valid, otherwise default to Employed.
            // - If user only has one type, force that type.
            setRecordViewType(prev => {
                if (hasEmployed && hasSelfEmployed) {
                    return prev === 'Self-employed' ? 'Self-employed' : 'Employed';
                }
                if (hasEmployed) return 'Employed';
                if (hasSelfEmployed) return 'Self-employed';
                return 'Employed';
            });

            setSelectedStatus(typedRecords[0].employment_status as EmploymentStatus);
            setShowStatusSelector(false);
        } else {
            setShowStatusSelector(true);
        }

    } catch (error: any) {
        console.error("Error fetching records:", error.message || error);
    } finally {
        setLoadingRecords(false);
    }
  };

  useEffect(() => {
    fetchEmploymentRecords();
  }, [user.id]); // Re-fetch if user changes, basically on mount

  // Reset detection when crucial fields change
  useEffect(() => {
    if (viewMode === 'form') {
        setIsNonRelatedDetected(false);
    }
  }, [formData.current_position, formData.company_name, formData.business_name, formData.business_type]);


  // --- Event Handlers ---

  const handleStatusSelect = (status: EmploymentStatus) => {
      // Logic: If user is currently employed/self-employed and selects Unemployed or Retired, trigger transition flow
      const isCurrentlyActive = employmentRecords.some(r => 
          r.employment_status === 'Employed' || r.employment_status === 'Self-employed'
      );

      const isSwitchingToInactive = status === 'Unemployed' || status === 'Retired';

      if (isCurrentlyActive && isSwitchingToInactive) {
          setPendingStatus(status);
          setShowTransitionModal(true);
          return;
      }

      // Normal Flow
      setFormData({ ...initialFormState, employment_status: status });
      setViewMode('form');
      setShowStatusSelector(false);
      setIsNonRelatedDetected(false);
  };

  const confirmTransition = async () => {
    if (!pendingStatus) return;
    setSubmitting(true);

    try {
        // 1. Identify active records to archive
        const activeRecords = employmentRecords.filter(r => 
            r.employment_status === 'Employed' || r.employment_status === 'Self-employed'
        );

        // 2. Archive to Employment History table
        const historyPayloads = activeRecords.map(record => ({
            survey_response_id: record.survey_response_id,
            employment_status: record.employment_status,
            position: record.current_position || 'Owner', // Fallback
            company_name: record.company_name,
            company_address: record.company_address,
            job_level: record.current_job_level,
            date_hired: record.date_hired,
            business_name: record.business_name,
            business_address: record.business_address,
            business_type: record.business_type,
            industry: record.industry,
            job_alignment: record.job_alignment,
            is_current_job: false // Marking as past job
        }));

        if (historyPayloads.length > 0) {
            const { error: histError } = await supabase
                .from('employment_history')
                .insert(historyPayloads);
            if (histError) throw histError;
        }

        // 3. Delete from active Employment Information table
        const idsToDelete = activeRecords.map(r => r.id);
        if (idsToDelete.length > 0) {
            const { error: delError } = await supabase
                .from('employment_information')
                .delete()
                .in('id', idsToDelete);
            if (delError) throw delError;
        }

        // 4. Reset UI and Open Form for new Status
        setFormData({ ...initialFormState, employment_status: pendingStatus });
        setViewMode('form');
        setShowStatusSelector(false);
        setShowTransitionModal(false);

        // Refresh local list (it should be empty now for active records)
        await fetchEmploymentRecords();

    } catch (error: any) {
        console.error("Transition Error:", error);
        alert("Failed to update status: " + error.message);
    } finally {
        setSubmitting(false);
    }
  };

  const handleAddJob = () => {
      setFormData({ ...initialFormState, employment_status: 'Employed' });
      setViewMode('form');
      setIsNonRelatedDetected(false);
  };

  const handleAddBusiness = () => {
      setFormData({ ...initialFormState, employment_status: 'Self-employed' });
      setViewMode('form');
      setIsNonRelatedDetected(false);
  };

  const handleEdit = (record: EmploymentRecord) => {
      setFormData(record);
      setViewMode('form');
      setIsNonRelatedDetected(record.job_alignment === 'Non-Related');
  };

  const handleDelete = async (id: string) => {
      if (!confirm("Are you sure you want to delete this record?")) return;
      try {
          const { error } = await supabase.from('employment_information').delete().eq('id', id);
          if (error) throw error;
          fetchEmploymentRecords();
      } catch (error) {
          console.error("Error deleting record:", error);
          alert("Failed to delete record.");
      }
  };

  const handleInputChange = (field: keyof EmploymentFormState, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleEmploymentSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);

    try {
      if (!user.id) throw new Error("User ID missing");

      // Initialize with null/neutral values so it doesn't default to Non-Related immediately
      let aiResult = { job_alignment: null as string | null, current_job_level: null as string | null, industry: null as string | null };

      // 1. AI Analysis
      if (formData.employment_status === 'Employed') {
        // @ts-ignore
        aiResult = await analyzeJobDetails(formData.current_position, formData.company_name, user.program, 'Employed');
      } else if (formData.employment_status === 'Self-employed') {
        // @ts-ignore
        aiResult = await analyzeJobDetails('Owner/Proprietor', formData.business_name, user.program, 'Self-employed');
      }

      // 2. Non-Related Check
      // Only apply this check if the user is Employed or Self-employed
      if (
          (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') &&
          aiResult.job_alignment === 'Non-Related' && 
          !formData.alignment_reason
         ) {
          setIsNonRelatedDetected(true);
          setSubmitting(false);
          alert("Action Required: The system detected that this role might be Non-Related to your course. Please scroll up/down to the 'System detected' section and select a reason.");
          return;
      }

      // 3. Prepare Payload
      const respondentType = user.enrollment_status === 'Graduating' ? 'student' : 'alumni';
      let surveyResponseId = '';

      if (formData.id) {
          // UPDATE EXISTING RECORD
          const updatePayload: any = {
              employment_status: formData.employment_status,

              job_alignment: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.job_alignment : null,
              current_job_level: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.current_job_level : null,
              industry: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.industry : null,

              current_position: formData.employment_status === 'Employed' ? formData.current_position : null,
              date_hired: formData.employment_status === 'Employed' ? formData.date_hired : null,
              company_name: formData.employment_status === 'Employed' ? formData.company_name : null,
              company_address: formData.employment_status === 'Employed' ? formData.company_address : null,

              business_name: formData.employment_status === 'Self-employed' ? formData.business_name : null,
              business_address: formData.employment_status === 'Self-employed' ? formData.business_address : null,
              business_type: formData.employment_status === 'Self-employed' ? formData.business_type : null,
              business_contact_no: formData.employment_status === 'Self-employed' ? formData.business_contact_no : null,
              business_duration: formData.employment_status === 'Self-employed' ? formData.business_duration : null,

              unemployed_reasons: formData.employment_status === 'Unemployed' ? formData.unemployed_reasons : null,

              last_company: formData.employment_status === 'Retired' ? formData.last_company : null,
              retirement_reason: formData.employment_status === 'Retired' ? formData.retirement_reason : null,
              date_retired: formData.employment_status === 'Retired' ? formData.date_retired : null,

              // Save alignment reason ONLY if AI says Non-Related
              alignment_reason: ((formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') && aiResult.job_alignment === 'Non-Related') ? formData.alignment_reason : null,
          };

          const { error } = await supabase.from('employment_information').update(updatePayload).eq('id', formData.id);
          if (error) throw error;

      } else {
          // CREATE NEW RECORD
          const surveyPayload: any = {
            respondent_type: respondentType,
            submitted_at: new Date().toISOString()
          };
          if (respondentType === 'student') surveyPayload.student_id = user.id;
          else surveyPayload.alumni_id = user.id;

          const { data: surveyData, error: surveyError } = await supabase
            .from('survey_responses')
            .insert([surveyPayload])
            .select()
            .single();

          if (surveyError) throw surveyError;
          surveyResponseId = surveyData.id;

          // --- AUTOMATIC CLEANUP OF CONFLICTING STATUSES ---
          const statusToCheck = formData.employment_status;
          const recordsToDelete: string[] = [];

          if (statusToCheck === 'Unemployed' || statusToCheck === 'Retired') {
              // If becoming Unemployed or Retired, remove all other records to ensure exclusivity
              employmentRecords.forEach(r => {
                  recordsToDelete.push(r.id);
              });
          } else if (statusToCheck === 'Employed' || statusToCheck === 'Self-employed') {
              // If becoming Employed/Self-employed, remove Unemployed or Retired records
              // BUT DO NOT remove other Employed/Self-employed records
              employmentRecords.forEach(r => {
                  if (r.employment_status === 'Unemployed' || r.employment_status === 'Retired') {
                      recordsToDelete.push(r.id);
                  }
              });
          }

          if (recordsToDelete.length > 0) {
              const { error: delErr } = await supabase
                .from('employment_information')
                .delete()
                .in('id', recordsToDelete);
              if (delErr) console.error("Cleanup error:", delErr);
          }
          // --- END CLEANUP ---

          const insertPayload = {
            survey_response_id: surveyResponseId,
            employment_status: formData.employment_status,

            job_alignment: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.job_alignment : null,
            current_job_level: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.current_job_level : null,
            industry: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.industry : null,

            current_position: formData.employment_status === 'Employed' ? formData.current_position : null,
            date_hired: formData.employment_status === 'Employed' ? formData.date_hired : null,
            company_name: formData.employment_status === 'Employed' ? formData.company_name : null,
            company_address: formData.employment_status === 'Employed' ? formData.company_address : null,

            business_name: formData.employment_status === 'Self-employed' ? formData.business_name : null,
            business_address: formData.employment_status === 'Self-employed' ? formData.business_address : null,
            business_type: formData.employment_status === 'Self-employed' ? formData.business_type : null,
            business_contact_no: formData.employment_status === 'Self-employed' ? formData.business_contact_no : null,
            business_duration: formData.employment_status === 'Self-employed' ? formData.business_duration : null,

            unemployed_reasons: formData.employment_status === 'Unemployed' ? formData.unemployed_reasons : null,

            last_company: formData.employment_status === 'Retired' ? formData.last_company : null,
            retirement_reason: formData.employment_status === 'Retired' ? formData.retirement_reason : null,
            date_retired: formData.employment_status === 'Retired' ? formData.date_retired : null,

            alignment_reason: ((formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') && aiResult.job_alignment === 'Non-Related') ? formData.alignment_reason : null,
          };

          const { error: empError } = await supabase.from('employment_information').insert([insertPayload]);
          if (empError) throw empError;
      }

      await fetchEmploymentRecords();

      // Force switch the view tab to match the status we just added/updated
      if (formData.employment_status === 'Employed') setRecordViewType('Employed');
      if (formData.employment_status === 'Self-employed') setRecordViewType('Self-employed');

      setViewMode('list');
      setIsNonRelatedDetected(false);
      alert("Status updated successfully!");

    } catch (err: any) {
      console.error("Submission error:", err);
      alert("Failed to save information: " + err.message);
    } finally {
      setSubmitting(false);
    }
  };

  const cancelForm = () => {
      setViewMode('list');
      if (employmentRecords.length > 0) {
          setShowStatusSelector(false);
      }
      setIsNonRelatedDetected(false);
  };

  // Status Logic
  const hasEmployed = employmentRecords.some(r => r.employment_status === 'Employed');
  const hasSelfEmployed = employmentRecords.some(r => r.employment_status === 'Self-employed');
  const hasUnemployed = employmentRecords.some(r => r.employment_status === 'Unemployed');
  const hasRetired = employmentRecords.some(r => r.employment_status === 'Retired');

  // Filter Logic
  const filteredRecords = employmentRecords.filter(record => {
      if (recordViewType === 'Employed') return record.employment_status === 'Employed';
      if (recordViewType === 'Self-employed') return record.employment_status === 'Self-employed';
      return false;
  });

  // Handle other statuses for the list view (Unemployed/Retired don't need toggle usually, but let's handle them)
  const otherRecords = employmentRecords.filter(r => r.employment_status === 'Unemployed' || r.employment_status === 'Retired');

  // RENDER JSX (Copied from Dashboard.tsx's `activeTab === 'employment'` block)
  return (
    <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden animate-slide-up relative min-h-[500px]">

        {/* === TRANSITION MODAL === */}
        {showTransitionModal && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-gray-900/40 backdrop-blur-md animate-in fade-in duration-300" onClick={() => setShowTransitionModal(false)}></div>
                <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md relative z-10 overflow-hidden animate-in zoom-in-95 duration-300 border border-white/20">
                    <div className="p-8">
                        <div className="w-16 h-16 bg-amber-50 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner">
                             <AlertTriangle className="w-8 h-8 text-amber-500" />
                        </div>
                        <h3 className="text-2xl font-black text-center text-gray-800 mb-2">Change Job Status?</h3>
                        <p className="text-gray-500 text-center text-sm mb-6 leading-relaxed">
                            Are you sure you want to change your status to <strong className="text-gray-800">{pendingStatus}</strong>? 
                            <br/><br/>
                            Your current employment records will be <strong>archived to your profile history</strong> and removed from your active status.
                        </p>

                        <div className="space-y-3">
                            <button 
                                onClick={confirmTransition}
                                disabled={submitting}
                                className="w-full py-3.5 bg-amber-500 hover:bg-amber-600 text-white font-bold rounded-xl shadow-lg shadow-amber-200/50 transition-all text-sm flex items-center justify-center gap-2"
                            >
                                {submitting ? <Loader2 size={18} className="animate-spin" /> : "Yes, Update Status"}
                            </button>
                            <button 
                                onClick={() => setShowTransitionModal(false)}
                                disabled={submitting}
                                className="w-full py-3.5 bg-gray-100 hover:bg-gray-200 text-gray-700 font-bold rounded-xl transition-colors text-sm"
                            >
                                Cancel
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        )}

        <div className="p-8 border-b border-gray-100 bg-gradient-to-r from-gray-50 to-white flex justify-between items-center">
            <div className="flex items-center gap-4">
                    <div className="p-3 bg-amber-100 text-amber-600 rounded-xl">
                    <Briefcase size={28} />
                    </div>
                    <div>
                    <h3 className="text-2xl font-bold text-gray-800 font-display">Employment Status</h3>
                    <p className="text-sm text-gray-500 mt-1">Manage your professional journey.</p>
                    </div>
            </div>
            {viewMode === 'form' && (
                <button onClick={cancelForm} className="flex items-center gap-2 bg-gray-100 text-gray-600 px-4 py-2 rounded-xl text-sm font-bold hover:bg-gray-200 transition-all">
                    <X size={16} /> Cancel
                </button>
            )}
        </div>

        {/* Content Body */}
        <div className="p-8">
            {loadingRecords ? (
                    <div className="flex flex-col items-center justify-center py-12 text-gray-400">
                    <Loader2 className="w-8 h-8 animate-spin mb-2" />
                    <p>Loading records...</p>
                </div>
            ) : viewMode === 'list' ? (
                <div className="space-y-8 animate-fade-in">

                    {/* Current Status & Header Section */}
                    {employmentRecords.length > 0 && !showStatusSelector && (
                        <div className="bg-green-50 rounded-2xl p-6 border border-green-100 flex flex-col md:flex-row justify-between items-center gap-4">
                            <div>
                                <h4 className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-1">Current Status</h4>
                                <div className="flex items-center gap-3">
                                    <div className="p-2 rounded-lg bg-green-200 text-luGreen-dark">
                                        <Briefcase size={20} />
                                    </div>
                                    <span className="text-xl font-bold text-gray-800">
                                        {hasEmployed && hasSelfEmployed ? 'Employed & Self-employed' :
                                            hasEmployed ? 'Employed' :
                                            hasSelfEmployed ? 'Self-employed' :
                                            hasRetired ? 'Retired' :
                                            hasUnemployed ? 'Unemployed' : 'Unknown'}
                                    </span>
                                </div>
                            </div>

                            <div className="flex gap-2 w-full md:w-auto">
                                {/* Allow adding both types if one is active, or both */}
                                {(hasEmployed || hasSelfEmployed) && (
                                    <>
                                    <button onClick={handleAddJob} className="flex-1 md:flex-initial flex items-center justify-center gap-2 bg-white text-gray-700 border border-gray-200 hover:border-blue-300 hover:text-blue-600 px-4 py-2.5 rounded-xl text-sm font-bold shadow-sm transition-all">
                                        <Plus size={16} /> Add Job
                                    </button>
                                    <button onClick={handleAddBusiness} className="flex-1 md:flex-initial flex items-center justify-center gap-2 bg-white text-gray-700 border border-gray-200 hover:border-purple-300 hover:text-purple-600 px-4 py-2.5 rounded-xl text-sm font-bold shadow-sm transition-all">
                                        <Plus size={16} /> Add Business
                                    </button>
                                    </>
                                )}
                                <button 
                                    onClick={() => setShowStatusSelector(true)}
                                    className="flex-1 md:flex-initial flex items-center justify-center gap-2 bg-gray-800 text-white px-4 py-2.5 rounded-xl text-sm font-bold shadow-md hover:bg-gray-900 transition-all"
                                >
                                    <RefreshCw size={16} /> Update Status
                                </button>
                            </div>
                        </div>
                    )}

                    {/* Status Selector (Empty State or Update Mode) */}
                    {showStatusSelector && (
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 animate-fade-in-up">
                            {[
                                { status: 'Employed', icon: Briefcase, color: 'blue', desc: 'Working for a company/organization' },
                                { status: 'Self-employed', icon: Building2, color: 'purple', desc: 'Running your own business' },
                                { status: 'Unemployed', icon: AlertTriangle, color: 'red', desc: 'Currently looking for work' },
                                { status: 'Retired', icon: Clock, color: 'gray', desc: 'No longer in the workforce' }
                            ].map((opt) => (
                                <button 
                                    key={opt.status}
                                    onClick={() => handleStatusSelect(opt.status as EmploymentStatus)}
                                    className={`p-6 rounded-2xl border-2 transition-all hover:scale-[1.02] text-left group
                                        ${opt.color === 'blue' ? 'border-blue-100 bg-blue-50/50 hover:border-blue-300' : ''}
                                        ${opt.color === 'purple' ? 'border-purple-100 bg-purple-50/50 hover:border-purple-300' : ''}
                                        ${opt.color === 'red' ? 'border-red-100 bg-red-50/50 hover:border-red-300' : ''}
                                        ${opt.color === 'gray' ? 'border-gray-100 bg-gray-50/50 hover:border-gray-300' : ''}
                                    `}
                                >
                                    <div className={`w-12 h-12 rounded-xl flex items-center justify-center mb-4 transition-colors
                                        ${opt.color === 'blue' ? 'bg-blue-100 text-blue-600 group-hover:bg-blue-600 group-hover:text-white' : ''}
                                        ${opt.color === 'purple' ? 'bg-purple-100 text-purple-600 group-hover:bg-purple-600 group-hover:text-white' : ''}
                                        ${opt.color === 'red' ? 'bg-red-100 text-red-600 group-hover:bg-red-600 group-hover:text-white' : ''}
                                        ${opt.color === 'gray' ? 'bg-gray-200 text-gray-600 group-hover:bg-gray-600 group-hover:text-white' : ''}
                                    `}>
                                        <opt.icon size={24} />
                                    </div>
                                    <h5 className="font-bold text-gray-800 text-lg">{opt.status}</h5>
                                    <p className="text-xs text-gray-500 mt-1">{opt.desc}</p>
                                </button>
                            ))}
                        </div>
                    )}

                    {/* Records List */}
                    {employmentRecords.length > 0 && !showStatusSelector && (
                        <div>
                             {/* Tabs for Employed vs Self-Employed if both exist */}
                            {(hasEmployed && hasSelfEmployed) && (
                                <div className="flex gap-4 border-b border-gray-100 mb-6">
                                    <button 
                                        onClick={() => setRecordViewType('Employed')}
                                        className={`pb-2 text-sm font-bold border-b-2 transition-colors ${recordViewType === 'Employed' ? 'border-luGreen text-luGreen' : 'border-transparent text-gray-400 hover:text-gray-600'}`}
                                    >
                                        Employed Records
                                    </button>
                                    <button 
                                        onClick={() => setRecordViewType('Self-employed')}
                                        className={`pb-2 text-sm font-bold border-b-2 transition-colors ${recordViewType === 'Self-employed' ? 'border-luGreen text-luGreen' : 'border-transparent text-gray-400 hover:text-gray-600'}`}
                                    >
                                        Business Records
                                    </button>
                                </div>
                            )}

                            {filteredRecords.length === 0 && otherRecords.length === 0 ? (
                                <div className="text-center py-10 bg-gray-50 rounded-2xl border border-gray-100 border-dashed">
                                    <p className="text-gray-400 text-sm font-semibold">No active records found for this category.</p>
                                </div>
                            ) : (
                                <div className="grid grid-cols-1 gap-6">
                                    {/* Active Records (Enhanced) */}
                                    {filteredRecords.map(record => (
                                        <div key={record.id} className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-all group relative overflow-hidden">

                                            {/* Top Row: Badges & Actions */}
                                            <div className="flex justify-between items-start mb-4">
                                                <div className="flex flex-wrap gap-2">
                                                    <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide border ${
                                                        record.employment_status === 'Employed' 
                                                        ? 'bg-blue-50 text-blue-600 border-blue-100' 
                                                        : 'bg-purple-50 text-purple-600 border-purple-100'
                                                    }`}>
                                                        {record.employment_status}
                                                    </span>

                                                    {/* Job Alignment Badge */}
                                                    {record.job_alignment && (
                                                        <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide border ${
                                                            record.job_alignment === 'Related' 
                                                            ? 'bg-green-50 text-green-600 border-green-100' 
                                                            : 'bg-amber-50 text-amber-600 border-amber-100'
                                                        }`}>
                                                            {record.job_alignment}
                                                        </span>
                                                    )}
                                                </div>

                                                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity absolute top-6 right-6 bg-white pl-2">
                                                    <button onClick={() => handleEdit(record)} className="p-2 text-gray-400 hover:text-luGreen hover:bg-green-50 rounded-lg transition-colors" title="Edit">
                                                        <Edit2 size={16} />
                                                    </button>
                                                    <button onClick={() => handleDelete(record.id)} className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors" title="Delete">
                                                        <Trash2 size={16} />
                                                    </button>
                                                </div>
                                            </div>

                                            {/* Main Content: Position & Company */}
                                            <div className="mb-6">
                                                <h4 className="text-xl font-bold text-gray-800 leading-tight mb-1">
                                                    {record.current_position || 'Owner / Proprietor'}
                                                </h4>
                                                <p className="text-base font-medium text-gray-500 flex items-center gap-2">
                                                    {record.employment_status === 'Self-employed' ? (
                                                         <><Building2 size={16} className="text-purple-400"/> {record.business_name}</>
                                                    ) : (
                                                         <><Briefcase size={16} className="text-blue-400"/> {record.company_name}</>
                                                    )}
                                                </p>
                                            </div>

                                            {/* Details Grid (Symmetrical) */}
                                            <div className="grid grid-cols-2 gap-y-4 gap-x-8 pt-4 border-t border-gray-50">
                                                {/* Industry */}
                                                <div className="flex flex-col gap-1">
                                                    <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider flex items-center gap-1"><Layers size={10} /> Industry</span>
                                                    <span className="text-sm font-semibold text-gray-700 truncate" title={record.industry || 'N/A'}>
                                                        {record.industry || 'Not Specified'}
                                                    </span>
                                                </div>

                                                {/* Job Level */}
                                                <div className="flex flex-col gap-1">
                                                    <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider flex items-center gap-1"><Award size={10} /> Job Level</span>
                                                    <span className="text-sm font-semibold text-gray-700 truncate" title={record.current_job_level || 'N/A'}>
                                                        {record.current_job_level || 'N/A'}
                                                    </span>
                                                </div>

                                                {/* Location */}
                                                <div className="flex flex-col gap-1">
                                                    <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider flex items-center gap-1"><MapPin size={10} /> Location</span>
                                                    <span className="text-sm font-semibold text-gray-700 truncate" title={record.company_address || record.business_address || 'N/A'}>
                                                        {record.company_address || record.business_address || 'Not Specified'}
                                                    </span>
                                                </div>

                                                {/* Date / Duration */}
                                                <div className="flex flex-col gap-1">
                                                    <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider flex items-center gap-1"><Calendar size={10} /> {record.employment_status === 'Self-employed' ? 'Duration' : 'Date Hired'}</span>
                                                    <span className="text-sm font-semibold text-gray-700 truncate">
                                                        {record.date_hired || record.business_duration || 'N/A'}
                                                    </span>
                                                </div>
                                            </div>

                                            {/* Optional: Alignment Reason if Non-Related */}
                                            {record.alignment_reason && (
                                                <div className="mt-4 p-3 bg-amber-50 rounded-xl border border-amber-100 flex items-start gap-2">
                                                    <AlertTriangle size={14} className="text-amber-500 mt-0.5 shrink-0" />
                                                    <div className="flex flex-col">
                                                        <span className="text-[10px] font-bold text-amber-700 uppercase">Misalignment Reason</span>
                                                        <span className="text-xs font-medium text-amber-800">{record.alignment_reason}</span>
                                                    </div>
                                                </div>
                                            )}
                                        </div>
                                    ))}

                                    {/* Other Records (Unemployed/Retired) */}
                                    {otherRecords.map(record => (
                                         <div key={record.id} className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-all group relative overflow-hidden">

                                            <div className="flex justify-between items-start mb-4">
                                                 <div className="flex items-center gap-2 mb-1">
                                                        <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide border ${
                                                            record.employment_status === 'Unemployed' 
                                                            ? 'bg-red-50 text-red-600 border-red-100' 
                                                            : 'bg-gray-100 text-gray-600 border-gray-200'
                                                        }`}>
                                                            {record.employment_status}
                                                        </span>
                                                </div>
                                                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity absolute top-6 right-6 bg-white pl-2">
                                                    <button onClick={() => handleEdit(record)} className="p-2 text-gray-400 hover:text-luGreen hover:bg-green-50 rounded-lg transition-colors" title="Edit">
                                                        <Edit2 size={16} />
                                                    </button>
                                                    <button onClick={() => handleDelete(record.id)} className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors" title="Delete">
                                                        <Trash2 size={16} />
                                                    </button>
                                                </div>
                                            </div>

                                            <div className="mb-6">
                                                <h4 className="text-xl font-bold text-gray-800 leading-tight mb-1">
                                                    {record.employment_status === 'Retired' ? 'Retired' : 'Currently Unemployed'}
                                                </h4>
                                                <p className="text-base font-medium text-gray-500">
                                                    {record.employment_status === 'Retired' ? `Retired from ${record.last_company}` : 'Not currently employed'}
                                                </p>
                                            </div>

                                            <div className="grid grid-cols-2 gap-y-4 gap-x-8 pt-4 border-t border-gray-50">
                                                <div className="flex flex-col gap-1">
                                                    <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider">
                                                        {record.employment_status === 'Retired' ? 'Reason for Retirement' : 'Reason for Unemployment'}
                                                    </span>
                                                    <span className="text-sm font-semibold text-gray-700 truncate">
                                                        {record.retirement_reason || record.unemployed_reasons || 'N/A'}
                                                    </span>
                                                </div>
                                                {record.employment_status === 'Retired' && (
                                                    <div className="flex flex-col gap-1">
                                                        <span className="text-[10px] uppercase font-bold text-gray-400 tracking-wider">Date Retired</span>
                                                        <span className="text-sm font-semibold text-gray-700 truncate">
                                                            {record.date_retired || 'N/A'}
                                                        </span>
                                                    </div>
                                                )}
                                            </div>
                                         </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    )}
                </div>
            ) : (
                <form onSubmit={handleEmploymentSubmit} className="animate-fade-in space-y-6">
                    {/* Status Indicator */}
                    <div className="flex items-center gap-2 mb-2">
                        <span className="text-xs font-bold text-gray-400 uppercase">Selected Status:</span>
                        <span className="px-3 py-1 bg-gray-900 text-white rounded-full text-xs font-bold">
                            {formData.employment_status}
                        </span>
                    </div>

                    {/* Dynamic Fields based on Status */}
                    {formData.employment_status === 'Employed' && (
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-gray-500 uppercase">Job Title / Position</label>
                                <input required type="text" value={formData.current_position} onChange={e => handleInputChange('current_position', e.target.value)} className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200 focus:border-luGreen outline-none font-semibold text-sm"/>
                            </div>
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-gray-500 uppercase">Company Name</label>
                                <input required type="text" value={formData.company_name} onChange={e => handleInputChange('company_name', e.target.value)} className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200 focus:border-luGreen outline-none font-semibold text-sm"/>
                            </div>
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-gray-500 uppercase">Company Address</label>
                                <input required type="text" value={formData.company_address} onChange={e => handleInputChange('company_address', e.target.value)} className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200 focus:border-luGreen outline-none font-semibold text-sm"/>
                            </div>
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-gray-500 uppercase">Date Hired</label>
                                <input required type="date" value={formData.date_hired} onChange={e => handleInputChange('date_hired', e.target.value)} className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200 focus:border-luGreen outline-none font-semibold text-sm"/>
                            </div>
                        </div>
                    )}

                    {formData.employment_status === 'Self-employed' && (
                        <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-gray-500 uppercase">Business Name</label>
                                <input required type="text" value={formData.business_name} onChange={e => handleInputChange('business_name', e.target.value)} className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200 focus:border-luGreen outline-none font-semibold text-sm"/>
                            </div>
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-gray-500 uppercase">Business Type / Industry</label>
                                <input required type="text" value={formData.business_type} onChange={e => handleInputChange('business_type', e.target.value)} className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200 focus:border-luGreen outline-none font-semibold text-sm"/>
                            </div>
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-gray-500 uppercase">Business Address</label>
                                <input required type="text" value={formData.business_address} onChange={e => handleInputChange('business_address', e.target.value)} className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200 focus:border-luGreen outline-none font-semibold text-sm"/>
                            </div>
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-gray-500 uppercase">Contact Number</label>
                                <input type="text" value={formData.business_contact_no} onChange={e => handleInputChange('business_contact_no', e.target.value)} className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200 focus:border-luGreen outline-none font-semibold text-sm"/>
                            </div>
                        </div>
                    )}

                    {formData.employment_status === 'Unemployed' && (
                         <div className="space-y-2">
                            <label className="text-xs font-bold text-gray-500 uppercase">Reason for Unemployment</label>
                            <select required value={formData.unemployed_reasons} onChange={e => handleInputChange('unemployed_reasons', e.target.value)} className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200 focus:border-luGreen outline-none font-semibold text-sm">
                                <option value="">Select Reason</option>
                                <option value="Advance Studies">Advance Studies</option>
                                <option value="Family Concerns">Family Concerns</option>
                                <option value="Health Related">Health Related</option>
                                <option value="Lack of Experience">Lack of Work Experience</option>
                                <option value="No Job Opportunity">No Job Opportunity</option>
                                <option value="Did not look for job">Did not look for a job</option>
                            </select>
                        </div>
                    )}

                     {formData.employment_status === 'Retired' && (
                         <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
                            <div className="space-y-2">
                                <label className="text-xs font-bold text-gray-500 uppercase">Date Retired</label>
                                <input required type="date" value={formData.date_retired} onChange={e => handleInputChange('date_retired', e.target.value)} className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200 focus:border-luGreen outline-none font-semibold text-sm"/>
                            </div>
                             <div className="space-y-2">
                                <label className="text-xs font-bold text-gray-500 uppercase">Last Company</label>
                                <input required type="text" value={formData.last_company} onChange={e => handleInputChange('last_company', e.target.value)} className="w-full p-3 bg-gray-50 rounded-xl border border-gray-200 focus:border-luGreen outline-none font-semibold text-sm"/>
                            </div>
                        </div>
                    )}

                    {/* Non-Related Reason Section - Shows only if detected */}
                    {isNonRelatedDetected && (
                        <div className="bg-amber-50 p-5 rounded-xl border border-amber-200 animate-fade-in">
                            <div className="flex gap-3 mb-3">
                                <AlertTriangle className="text-amber-500 shrink-0" />
                                <div>
                                    <h5 className="font-bold text-amber-800 text-sm">Course Misalignment Detected</h5>
                                    <p className="text-xs text-amber-700 mt-1">Our system detected that this role might not be aligned with your program ({user.program}). Please specify a reason:</p>
                                </div>
                            </div>
                            <select 
                                required 
                                value={formData.alignment_reason || ''} 
                                onChange={e => handleInputChange('alignment_reason', e.target.value)}
                                className="w-full p-3 bg-white border border-amber-300 rounded-xl text-sm font-semibold text-gray-700 outline-none focus:ring-2 focus:ring-amber-200"
                            >
                                <option value="">Select Reason...</option>
                                <option value="Better Salary/Benefits">Better Salary and Benefits</option>
                                <option value="Career Advancement">Career Advancement Opportunity</option>
                                <option value="No Job Opportunity">No Job Opportunity in Field</option>
                                <option value="Career Shift">Career Shift / Passion</option>
                                <option value="Family Influence">Family Influence</option>
                                <option value="Proximity">Proximity to Residence</option>
                            </select>
                        </div>
                    )}

                    {/* Submit Actions */}
                    <div className="pt-4 flex gap-3">
                        <button type="submit" disabled={submitting} className="flex-1 py-3.5 bg-luGreen text-white font-bold rounded-xl shadow-lg hover:shadow-green-200 hover:-translate-y-0.5 transition-all flex justify-center items-center gap-2">
                            {submitting ? <Loader2 size={18} className="animate-spin"/> : <Save size={18}/>}
                            Save Status
                        </button>
                        <button type="button" onClick={cancelForm} className="px-6 py-3.5 bg-gray-100 text-gray-600 font-bold rounded-xl hover:bg-gray-200 transition-colors">
                            Cancel
                        </button>
                    </div>
                </form>
            )}
        </div>
    </div>
  );
};

export default EmploymentStatusPage;

import React, { useEffect, useState } from 'react';
import { LogOut, User, BookOpen, Calendar, MapPin, Award, Bell, Search, ChevronDown, Briefcase, LayoutDashboard, Save, Loader2, CheckCircle, Plus, Trash2, Edit2, X, RefreshCw, Building2, ToggleLeft, ToggleRight, Clock, HelpCircle, AlertTriangle, ArrowRight, Layers } from 'lucide-react';
import { Student, EmploymentFormState, EmploymentRecord, EmploymentStatus } from '../types';
import { supabase } from '../lib/supabaseClient';
import { analyzeJobDetails } from '../services/employmentAI';

interface EmploymentStatusPageProps {
  user: Student;
}

const EmploymentStatusPage: React.FC<EmploymentStatusPageProps> = ({ user }) => {
  const [submitting, setSubmitting] = useState(false);
  const [loadingRecords, setLoadingRecords] = useState(false);
  const [employmentRecords, setEmploymentRecords] = useState<EmploymentRecord[]>([]);

  // View State
  const [viewMode, setViewMode] = useState<'list' | 'form'>('list');
  const [selectedStatus, setSelectedStatus] = useState<EmploymentStatus | null>(null);
  const [showStatusSelector, setShowStatusSelector] = useState(false);

  // Transition State
  const [showTransitionModal, setShowTransitionModal] = useState(false);
  const [pendingStatus, setPendingStatus] = useState<EmploymentStatus | null>(null);

  // New: Record View Toggle
  const [recordViewType, setRecordViewType] = useState<'Employed' | 'Self-employed'>('Employed');

  // New: Non-Related Detection State
  const [isNonRelatedDetected, setIsNonRelatedDetected] = useState(false);

  // Form State
  const initialFormState: EmploymentFormState = {
    employment_status: '',
    current_position: '',
    date_hired: '',
    company_name: '',
    company_address: '',
    business_name: '',
    business_address: '',
    business_type: '',
    business_contact_no: '',
    unemployed_reasons: '',
    last_company: '',
    retirement_reason: '',
    date_retired: '',
    business_duration: '',
    alignment_reason: ''
  };
  const [formData, setFormData] = useState<EmploymentFormState>(initialFormState);

  // --- Data Fetching ---
  const fetchEmploymentRecords = async () => {
    setLoadingRecords(true);
    try {
        if (!user.id) {
            console.warn("User ID is missing, cannot fetch records.");
            return;
        }

        const idColumn = user.enrollment_status === 'Graduating' ? 'student_id' : 'alumni_id';

        // 1. Get Survey Responses IDs for this user
        const { data: surveys, error: surveyError } = await supabase
            .from('survey_responses')
            .select('id')
            .eq(idColumn, user.id);

        if (surveyError) {
            console.error("Error fetching surveys:", JSON.stringify(surveyError));
            throw new Error(surveyError.message);
        }

        if (!surveys || surveys.length === 0) {
            setEmploymentRecords([]);
            setLoadingRecords(false);
            setShowStatusSelector(true); // Show selector if no records
            return;
        }

        const surveyIds = surveys.map(s => s.id);

        // 2. Get Employment Info linked to those surveys
        const { data: records, error: recordsError } = await supabase
            .from('employment_information')
            .select('*')
            .in('survey_response_id', surveyIds)
            .order('id', { ascending: false }); // Latest first

        if (recordsError) {
             console.error("Error fetching employment info:", JSON.stringify(recordsError));
             throw new Error(recordsError.message);
        }

        const typedRecords = records as EmploymentRecord[];
        setEmploymentRecords(typedRecords);

        // Logic for Initial View State
        if (typedRecords.length > 0) {
            const hasEmployed = typedRecords.some(r => r.employment_status === 'Employed');
            const hasSelfEmployed = typedRecords.some(r => r.employment_status === 'Self-employed');

            // Smartly set view type: 
            // - If user has both, keep current view if valid, otherwise default to Employed.
            // - If user only has one type, force that type.
            setRecordViewType(prev => {
                if (hasEmployed && hasSelfEmployed) {
                    return prev === 'Self-employed' ? 'Self-employed' : 'Employed';
                }
                if (hasEmployed) return 'Employed';
                if (hasSelfEmployed) return 'Self-employed';
                return 'Employed';
            });

            setSelectedStatus(typedRecords[0].employment_status as EmploymentStatus);
            setShowStatusSelector(false);
        } else {
            setShowStatusSelector(true);
        }

    } catch (error: any) {
        console.error("Error fetching records:", error.message || error);
    } finally {
        setLoadingRecords(false);
    }
  };

  useEffect(() => {
    fetchEmploymentRecords();
  }, [user.id]); // Re-fetch if user changes, basically on mount

  // Reset detection when crucial fields change
  useEffect(() => {
    if (viewMode === 'form') {
        setIsNonRelatedDetected(false);
    }
  }, [formData.current_position, formData.company_name, formData.business_name, formData.business_type]);


  // --- Event Handlers ---

  const handleStatusSelect = (status: EmploymentStatus) => {
      // Logic: If user is currently employed/self-employed and selects Unemployed or Retired, trigger transition flow
      const isCurrentlyActive = employmentRecords.some(r => 
          r.employment_status === 'Employed' || r.employment_status === 'Self-employed'
      );

      const isSwitchingToInactive = status === 'Unemployed' || status === 'Retired';

      if (isCurrentlyActive && isSwitchingToInactive) {
          setPendingStatus(status);
          setShowTransitionModal(true);
          return;
      }

      // Normal Flow
      setFormData({ ...initialFormState, employment_status: status });
      setViewMode('form');
      setShowStatusSelector(false);
      setIsNonRelatedDetected(false);
  };

  const confirmTransition = async () => {
    if (!pendingStatus) return;
    setSubmitting(true);

    try {
        // 1. Identify active records to archive
        const activeRecords = employmentRecords.filter(r => 
            r.employment_status === 'Employed' || r.employment_status === 'Self-employed'
        );

        // 2. Archive to Employment History table
        const historyPayloads = activeRecords.map(record => ({
            survey_response_id: record.survey_response_id,
            employment_status: record.employment_status,
            position: record.current_position || 'Owner', // Fallback
            company_name: record.company_name,
            company_address: record.company_address,
            job_level: record.current_job_level,
            date_hired: record.date_hired,
            business_name: record.business_name,
            business_address: record.business_address,
            business_type: record.business_type,
            industry: record.industry,
            job_alignment: record.job_alignment,
            is_current_job: false // Marking as past job
        }));

        if (historyPayloads.length > 0) {
            const { error: histError } = await supabase
                .from('employment_history')
                .insert(historyPayloads);
            if (histError) throw histError;
        }

        // 3. Delete from active Employment Information table
        const idsToDelete = activeRecords.map(r => r.id);
        if (idsToDelete.length > 0) {
            const { error: delError } = await supabase
                .from('employment_information')
                .delete()
                .in('id', idsToDelete);
            if (delError) throw delError;
        }

        // 4. Reset UI and Open Form for new Status
        setFormData({ ...initialFormState, employment_status: pendingStatus });
        setViewMode('form');
        setShowStatusSelector(false);
        setShowTransitionModal(false);

        // Refresh local list (it should be empty now for active records)
        await fetchEmploymentRecords();

    } catch (error: any) {
        console.error("Transition Error:", error);
        alert("Failed to update status: " + (error.message || String(error)));
    } finally {
        setSubmitting(false);
    }
  };

  const handleAddJob = () => {
      setFormData({ ...initialFormState, employment_status: 'Employed' });
      setViewMode('form');
      setIsNonRelatedDetected(false);
  };

  const handleAddBusiness = () => {
      setFormData({ ...initialFormState, employment_status: 'Self-employed' });
      setViewMode('form');
      setIsNonRelatedDetected(false);
  };

  const handleEdit = (record: EmploymentRecord) => {
      setFormData(record);
      setViewMode('form');
      setIsNonRelatedDetected(record.job_alignment === 'Non-Related');
  };

  const handleDelete = async (id: string) => {
      if (!confirm("Are you sure you want to delete this record?")) return;
      try {
          const { error } = await supabase.from('employment_information').delete().eq('id', id);
          if (error) throw error;
          fetchEmploymentRecords();
      } catch (error) {
          console.error("Error deleting record:", error);
          alert("Failed to delete record.");
      }
  };

  const handleInputChange = (field: keyof EmploymentFormState, value: string) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleEmploymentSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);

    try {
      if (!user.id) throw new Error("User ID missing");

      // Initialize with null/neutral values so it doesn't default to Non-Related immediately
      let aiResult = { job_alignment: null as string | null, current_job_level: null as string | null, industry: null as string | null };

      // 1. AI Analysis
      if (formData.employment_status === 'Employed') {
        // @ts-ignore
        aiResult = await analyzeJobDetails(formData.current_position, formData.company_name, user.program, 'Employed');
      } else if (formData.employment_status === 'Self-employed') {
        // @ts-ignore
        aiResult = await analyzeJobDetails('Owner/Proprietor', formData.business_name, user.program, 'Self-employed');
      }

      // 2. Non-Related Check
      // Only apply this check if the user is Employed or Self-employed
      if (
          (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') &&
          aiResult.job_alignment === 'Non-Related' && 
          !formData.alignment_reason
         ) {
          setIsNonRelatedDetected(true);
          setSubmitting(false);
          alert("Action Required: The system detected that this role might be Non-Related to your course. Please scroll up/down to the 'System detected' section and select a reason.");
          return;
      }

      // 3. Prepare Payload
      const respondentType = user.enrollment_status === 'Graduating' ? 'student' : 'alumni';
      let surveyResponseId = '';

      if (formData.id) {
          // UPDATE EXISTING RECORD
          const updatePayload: any = {
              employment_status: formData.employment_status,

              job_alignment: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.job_alignment : null,
              current_job_level: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.current_job_level : null,
              industry: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.industry : null,

              current_position: formData.employment_status === 'Employed' ? formData.current_position : null,
              date_hired: formData.employment_status === 'Employed' ? formData.date_hired : null,
              company_name: formData.employment_status === 'Employed' ? formData.company_name : null,
              company_address: formData.employment_status === 'Employed' ? formData.company_address : null,

              business_name: formData.employment_status === 'Self-employed' ? formData.business_name : null,
              business_address: formData.employment_status === 'Self-employed' ? formData.business_address : null,
              business_type: formData.employment_status === 'Self-employed' ? formData.business_type : null,
              business_contact_no: formData.employment_status === 'Self-employed' ? formData.business_contact_no : null,
              business_duration: formData.employment_status === 'Self-employed' ? formData.business_duration : null,

              unemployed_reasons: formData.employment_status === 'Unemployed' ? formData.unemployed_reasons : null,

              last_company: formData.employment_status === 'Retired' ? formData.last_company : null,
              retirement_reason: formData.employment_status === 'Retired' ? formData.retirement_reason : null,
              date_retired: formData.employment_status === 'Retired' ? formData.date_retired : null,

              // Save alignment reason ONLY if AI says Non-Related
              alignment_reason: ((formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') && aiResult.job_alignment === 'Non-Related') ? formData.alignment_reason : null,
          };

          const { error } = await supabase.from('employment_information').update(updatePayload).eq('id', formData.id);
          if (error) throw error;

      } else {
          // CREATE NEW RECORD
          const surveyPayload: any = {
            respondent_type: respondentType,
            submitted_at: new Date().toISOString()
          };
          if (respondentType === 'student') surveyPayload.student_id = user.id;
          else surveyPayload.alumni_id = user.id;

          const { data: surveyData, error: surveyError } = await supabase
            .from('survey_responses')
            .insert([surveyPayload])
            .select()
            .single();

          if (surveyError) throw surveyError;
          surveyResponseId = surveyData.id;

          // --- AUTOMATIC CLEANUP OF CONFLICTING STATUSES ---
          const statusToCheck = formData.employment_status;
          const recordsToDelete: string[] = [];

          if (statusToCheck === 'Unemployed' || statusToCheck === 'Retired') {
              // If becoming Unemployed or Retired, remove all other records to ensure exclusivity
              employmentRecords.forEach(r => {
                  recordsToDelete.push(r.id);
              });
          } else if (statusToCheck === 'Employed' || statusToCheck === 'Self-employed') {
              // If becoming Employed/Self-employed, remove Unemployed or Retired records
              // BUT DO NOT remove other Employed/Self-employed records
              employmentRecords.forEach(r => {
                  if (r.employment_status === 'Unemployed' || r.employment_status === 'Retired') {
                      recordsToDelete.push(r.id);
                  }
              });
          }

          if (recordsToDelete.length > 0) {
              const { error: delErr } = await supabase
                .from('employment_information')
                .delete()
                .in('id', recordsToDelete);
              if (delErr) console.error("Cleanup error:", delErr);
          }
          // --- END CLEANUP ---

          const insertPayload = {
            survey_response_id: surveyResponseId,
            employment_status: formData.employment_status,

            job_alignment: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.job_alignment : null,
            current_job_level: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.current_job_level : null,
            industry: (formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') ? aiResult.industry : null,

            current_position: formData.employment_status === 'Employed' ? formData.current_position : null,
            date_hired: formData.employment_status === 'Employed' ? formData.date_hired : null,
            company_name: formData.employment_status === 'Employed' ? formData.company_name : null,
            company_address: formData.employment_status === 'Employed' ? formData.company_address : null,

            business_name: formData.employment_status === 'Self-employed' ? formData.business_name : null,
            business_address: formData.employment_status === 'Self-employed' ? formData.business_address : null,
            business_type: formData.employment_status === 'Self-employed' ? formData.business_type : null,
            business_contact_no: formData.employment_status === 'Self-employed' ? formData.business_contact_no : null,
            business_duration: formData.employment_status === 'Self-employed' ? formData.business_duration : null,

            unemployed_reasons: formData.employment_status === 'Unemployed' ? formData.unemployed_reasons : null,

            last_company: formData.employment_status === 'Retired' ? formData.last_company : null,
            retirement_reason: formData.employment_status === 'Retired' ? formData.retirement_reason : null,
            date_retired: formData.employment_status === 'Retired' ? formData.date_retired : null,

            alignment_reason: ((formData.employment_status === 'Employed' || formData.employment_status === 'Self-employed') && aiResult.job_alignment === 'Non-Related') ? formData.alignment_reason : null,
          };

          const { error: empError } = await supabase.from('employment_information').insert([insertPayload]);
          if (empError) throw empError;
      }

      await fetchEmploymentRecords();

      // Force switch the view tab to match the status we just added/updated
      if (formData.employment_status === 'Employed') setRecordViewType('Employed');
      if (formData.employment_status === 'Self-employed') setRecordViewType('Self-employed');

      setViewMode('list');
      setIsNonRelatedDetected(false);
      alert("Status updated successfully!");

    } catch (err: any) {
      console.error("Submission error:", err);
      let errorMessage = "An unexpected error occurred.";

      if (err instanceof Error) {
          errorMessage = err.message;
      } else if (typeof err === 'object' && err !== null) {
          errorMessage = err.message || err.error_description || err.details || JSON.stringify(err);
      } else if (typeof err === 'string') {
          errorMessage = err;
      }

      alert("Failed to save information: " + errorMessage);
    } finally {
      setSubmitting(false);
    }
  };

  const cancelForm = () => {
      setViewMode('list');
      if (employmentRecords.length > 0) {
          setShowStatusSelector(false);
      }
      setIsNonRelatedDetected(false);
  };

  // Status Logic
  const hasEmployed = employmentRecords.some(r => r.employment_status === 'Employed');
  const hasSelfEmployed = employmentRecords.some(r => r.employment_status === 'Self-employed');
  const hasUnemployed = employmentRecords.some(r => r.employment_status === 'Unemployed');
  const hasRetired = employmentRecords.some(r => r.employment_status === 'Retired');

  // Filter Logic
  const filteredRecords = employmentRecords.filter(record => {
      if (recordViewType === 'Employed') return record.employment_status === 'Employed';
      if (recordViewType === 'Self-employed') return record.employment_status === 'Self-employed';
      return false;
  });

  // Handle other statuses for the list view (Unemployed/Retired don't need toggle usually, but let's handle them)
  const otherRecords = employmentRecords.filter(r => r.employment_status === 'Unemployed' || r.employment_status === 'Retired');

  // RENDER JSX (Copied from Dashboard.tsx's `activeTab === 'employment'` block)
  return (
    <div className="bg-white rounded-3xl shadow-sm border border-gray-100 overflow-hidden animate-slide-up relative min-h-[500px]">

        {/* === TRANSITION MODAL === */}
        {showTransitionModal && (
            <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
                <div className="absolute inset-0 bg-gray-900/40 backdrop-blur-md animate-in fade-in duration-300" onClick={() => setShowTransitionModal(false)}></div>
                <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md relative z-10 overflow-hidden animate-in zoom-in-95 duration-300 border border-white/20">
                    <div className="p-8">
                        <div className="w-16 h-16 bg-amber-50 rounded-full flex items-center justify-center mx-auto mb-6 shadow-inner">
                             <AlertTriangle className="w-8 h-8 text-amber-500" />
                        </div>
                        <h3 className="text-2xl font-black text-center text-gray-800 mb-2">Change Job Status?</h3>
                        <p className="text-gray-500 text-center text-sm mb-6 leading-relaxed">
                            Are you sure you want to change your status to <strong className="text-gray-800">{pendingStatus}</strong>? 
                            <br/><br/>
                            Your current employment records will be <strong>archived to your profile history</strong> and removed from your active status.
                        </p>

                        <div className="space-y-3">
                            <button 
                                onClick={confirmTransition}
                                disabled={submitting}
                                className="w-full py-3.5 bg-amber-500 hover:bg-amber-600 text-white font-bold rounded-xl shadow-lg shadow-amber-200/50 transition-all text-sm flex items-center justify-center gap-2"
                            >
                                {submitting ? <Loader2 size={18} className="animate-spin" /> : "Yes, Update Status"}
                            </button>
                            <button 
                                onClick={() => setShowTransitionModal(false)}
                                disabled={submitting}
                                className="w-full py-3.5 bg-gray-100 hover:bg-gray-200 text-gray-700 font-bold rounded-xl transition-colors text-sm"
                            >
                                Cancel
                            </button>
                        </div>
                    </div>
                </div>
            </div>
        )}

        <div className="p-8 border-b border-gray-100 bg-gradient-to-r from-gray-50 to-white flex justify-between items-center">
            <div className="flex items-center gap-4">
                    <div className="p-3 bg-amber-100 text-amber-600 rounded-xl">
                    <Briefcase size={28} />
                    </div>
                    <div>
                    <h3 className="text-2xl font-bold text-gray-800 font-display">Employment Status</h3>
                    <p className="text-sm text-gray-500 mt-1">Manage your professional journey.</p>
                    </div>
            </div>
            {viewMode === 'form' && (
                <button onClick={cancelForm} className="flex items-center gap-2 bg-gray-100 text-gray-600 px-4 py-2 rounded-xl text-sm font-bold hover:bg-gray-200 transition-all">
                    <X size={16} /> Cancel
                </button>
            )}
        </div>

        {/* Content Body */}
        <div className="p-8">
            {loadingRecords ? (
                    <div className="flex flex-col items-center justify-center py-12 text-gray-400">
                    <Loader2 className="w-8 h-8 animate-spin mb-2" />
                    <p>Loading records...</p>
                </div>
            ) : viewMode === 'list' ? (
                <div className="space-y-8 animate-fade-in">

                    {/* Current Status & Header Section */}
                    {employmentRecords.length > 0 && !showStatusSelector && (
                        <div className="bg-green-50 rounded-2xl p-6 border border-green-100 flex flex-col md:flex-row justify-between items-center gap-4">
                            <div>
                                <h4 className="text-xs font-bold text-gray-500 uppercase tracking-widest mb-1">Current Status</h4>
                                <div className="flex items-center gap-3">
                                    <div className="p-2 rounded-lg bg-green-200 text-luGreen-dark">
                                        <Briefcase size={20} />
                                    </div>
                                    <span className="text-xl font-bold text-gray-800">
                                        {hasEmployed && hasSelfEmployed ? 'Employed & Self-employed' :
                                            hasEmployed ? 'Employed' :
                                            hasSelfEmployed ? 'Self-employed' :
                                            hasRetired ? 'Retired' :
                                            hasUnemployed ? 'Unemployed' : 'Unknown'}
                                    </span>
                                </div>
                            </div>

                            <div className="flex gap-2 w-full md:w-auto">
                                {/* Allow adding both types if one is active, or both */}
