                                    {otherRecords.map(record => (
                                         <div key={record.id} className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-all group relative overflow-hidden">

                                            <div className="flex justify-between items-start mb-4">
                                                 <div className="flex items-center gap-2 mb-1">
                                                        <span className={`px-3 py-1 rounded-full text-[10px] font-bold uppercase tracking-wide border ${
                                                            record.employment_status === 'Unemployed' 
                                                            ? 'bg-red-50 text-red-600 border-red-100' 
                                                            : 'bg-gray-100 text-gray-600 border-gray-200'
                                                        }`}>
                                                            {record.employment_status}
                                                        </span>
                                                </div>
                                                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity absolute top-6 right-6 bg-white pl-2">
                                                    <button onClick={() => handleEdit(record)} className="p-2 text-gray-400 hover:text-luGreen hover:bg-green-50 rounded-lg transition-colors" title="Edit">
                                                        <Edit2 size={16} />
                                                    </button>
                                                    <button onClick={() => handleDelete(record.id)} className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors" title="Delete">
                                                        <Trash2 size={16} />
                                                    </button>
                                                </div>
                                            </div>

