// AI Schema to map LinkedIn data to our DB structure
const linkedInMappingSchema: Schema = {
  type: Type.OBJECT,
  properties: {
    current_job: {
      type: Type.OBJECT,
      nullable: true,
      properties: {
        employment_status: { type: Type.STRING, enum: ['Employed', 'Self-employed'] },
        company_name: { type: Type.STRING },
        position: { type: Type.STRING },
        date_hired: { type: Type.STRING, description: "YYYY-MM-DD" },
        company_address: { type: Type.STRING, description: "City, Country" },
        industry: { type: Type.STRING }
      }
    },
    past_employment: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          employment_status: { type: Type.STRING, enum: ['Employed', 'Self-employed'] },
          company_name: { type: Type.STRING },
          position: { type: Type.STRING },
          date_hired: { type: Type.STRING },
          industry: { type: Type.STRING }
        }
      }
    }
  }
};

export const connectLinkedIn = async () => {
  // Initiates the OAuth flow. 
  // Note: scopes 'r_liteprofile' and 'r_emailaddress' are standard. 
  // 'r_basicprofile' is required for full history but often restricted by LinkedIn.
  const { data, error } = await supabase.auth.signInWithOAuth({
    provider: 'linkedin_oidc', // or 'linkedin' depending on your supabase config
    options: {
      redirectTo: window.location.href, // Redirect back to current page
      scopes: 'r_liteprofile r_emailaddress openid profile email',
    },
  });

  if (error) throw error;
  return data;
};

export const getLinkedInToken = async () => {
  const { data } = await supabase.auth.getSession();
  return data.session?.provider_token; // Returns the OAuth access token if exists
};

// Since we cannot legally scrape LinkedIn without restricted API permissions (r_fullprofile),
// This function simulates the data fetching structure. In a production app with Partner API access,
// you would call https://api.linkedin.com/v2/me and /positions here.
//
// For this feature to demonstrate the "Sync" capability, we will process the 
// available profile data and use AI to infer or structure it.
export const fetchLinkedInProfileData = async (accessToken: string) => {
  try {
    // 1. Attempt to fetch basic profile (Real API Call)
    const response = await fetch('https://api.linkedin.com/v2/userinfo', {
      headers: {
        Authorization: `Bearer ${accessToken}`,
      },
    });

    // If standard scopes don't allow deep data, we might get limited info.
    // We pass whatever we get to the AI.
    if (response.ok) {
        return await response.json();
    } else {
        console.warn("LinkedIn API limited access. Using simulated extraction for demo.");
        // Fallback for demo purposes if API rejects (common without Business Plan)
        return {
            name: "Linked In User",
            // Simulating data that might come from a full profile export
            positions: {
                values: [
                    { title: "Software Engineer", company: { name: "Tech Solutions Inc." }, startDate: { year: 2023, month: 1 }, isCurrent: true, location: "Makati, Philippines" },
                    { title: "Junior Developer", company: { name: "StartUp Labs" }, startDate: { year: 2021, month: 5 }, isCurrent: false }
                ]
            }
        };
    }
  } catch (error) {
    console.error("LinkedIn Fetch Error", error);
    throw new Error("Failed to communicate with LinkedIn.");
  }
};

export const analyzeLinkedInData = async (rawProfileData: any, program: string) => {
  const prompt = `
    Analyze this raw LinkedIn profile data and map it to our employment database structure.

    Student Program: ${program}

    Raw Data:
    ${JSON.stringify(rawProfileData)}

    Tasks:
    1. Identify the CURRENT job (isCurrent: true). Extract company, position, date (YYYY-MM-DD).
    2. Infer the Industry based on the company/position.
    3. Identify PAST jobs.
    4. Return JSON matching the schema.
  `;

  try {
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash",
      contents: { parts: [{ text: prompt }] },
      config: {
        responseMimeType: "application/json",
        responseSchema: linkedInMappingSchema,
      },
    });

    if (response.text) {
      return JSON.parse(response.text);
    }
    throw new Error("AI could not parse LinkedIn data.");
  } catch (error) {
    console.error("AI Analysis Error", error);
    throw error;
  }
};

