export default MyProfilePage;

import React, { useState, useEffect } from 'react';
import { User, FileText, Upload, Save, Loader2, CheckCircle, School, Briefcase, Heart, Star, AlertCircle, ChevronDown, Plus, Trash2, X, MapPin, Mail, Phone, Edit3, AlertTriangle, GraduationCap, Award, BookOpen, ArrowRight, HelpCircle, Building2, Linkedin, Shield, Link as LinkIcon, ExternalLink, RefreshCw } from 'lucide-react';
import { Student, FullProfileData, EmploymentHistory, CommunityEngagement, EmploymentRecord } from '../types';
import FileUpload from './FileUpload';
import { parseResume, uploadResumeToDB, saveProfileData, deleteResumeFromDB, fetchLatestProfile, updateStudentProfile } from '../services/resumeService';
import { analyzeJobDetails } from '../services/employmentAI';
import { connectLinkedIn, getLinkedInToken, fetchLinkedInProfileData, analyzeLinkedInData } from '../services/linkedinService';
import { supabase } from '../lib/supabaseClient';

interface MyProfilePageProps {
  user: Student;
}

const MyProfilePage: React.FC<MyProfilePageProps> = ({ user }) => {
  const [loading, setLoading] = useState(false);
  const [fetching, setFetching] = useState(true);

  // Resume State
  const [parsing, setParsing] = useState(false);
  const [resumeUploaded, setResumeUploaded] = useState(false);
  const [verificationWarning, setVerificationWarning] = useState<string | null>(null);
  const [showDeleteModal, setShowDeleteModal] = useState(false);
  const [deletingResume, setDeletingResume] = useState(false);

  // LinkedIn State
  const [isLinkedInConnected, setIsLinkedInConnected] = useState(false);
  const [showPrivacyModal, setShowPrivacyModal] = useState(false);
  const [syncingLinkedIn, setSyncingLinkedIn] = useState(false);
  const [linkedInCandidate, setLinkedInCandidate] = useState<any>(null); // Result from AI
  const [showLinkedInResultModal, setShowLinkedInResultModal] = useState(false);

  // Current Job Verification State
  const [showCurrentJobModal, setShowCurrentJobModal] = useState(false);
  const [currentJobCandidate, setCurrentJobCandidate] = useState<Partial<EmploymentRecord> | null>(null);
  const [analyzingJob, setAnalyzingJob] = useState(false);
  const [savingCurrentJob, setSavingCurrentJob] = useState(false);
  const [misalignmentReason, setMisalignmentReason] = useState('');

  // UI State
  const [savedSuccess, setSavedSuccess] = useState(false);
  const [hasExistingRecord, setHasExistingRecord] = useState(false);
  const [activeSection, setActiveSection] = useState<string | null>(null);
  const [isEditingHeader, setIsEditingHeader] = useState(false);
  const [savingHeader, setSavingHeader] = useState(false);

  // Editable Personal Information State
  const [firstName, setFirstName] = useState(user.first_name);
  const [lastName, setLastName] = useState(user.last_name);
  const [email, setEmail] = useState(user.email);
  const [contactNo, setContactNo] = useState(user.contact_no);
  const [address, setAddress] = useState(user.address || '');
  const [program, setProgram] = useState(user.program);
  const [yearLevel, setYearLevel] = useState(user.year_level || '');

  // Profile Data State
  const [profileData, setProfileData] = useState<FullProfileData>({
    education: {},
    employment: [],
    community: [],
    attributes: {
        professionally_competent: 0,
        critical_thinker: 0,
        communicator: 0,
        lifelong_learner: 0,
        socially_responsible: 0,
        ethical_citizen: 0,
        innovative_worker: 0,
        people_oriented: 0,
        critical_thinking_skill: 0,
        creativity: 0,
        collaboration: 0,
        communication_skill: 0,
        information_literacy: 0,
        media_literacy: 0,
        technology_literacy: 0,
        flexibility: 0,
        leadership: 0,
        initiative: 0,
        productivity: 0,
        social_skills: 0
    }
  });

  // Load latest profile data & Resume Status on mount
  useEffect(() => {
    const loadData = async () => {
        if (!user.id) return;
        try {
            const userType = user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni';
            const table = userType === 'graduating' ? 'students' : 'alumni';

            // 1. Fetch Profile Info
            const data = await fetchLatestProfile(user.id, userType);
            if (data) {
                setProfileData(data);
                setHasExistingRecord(true);
            }

            // 2. Fetch Resume Existence
            const { data: resumeCheck } = await supabase
                .from(table)
                .select('id')
                .eq('id', user.id)
                .not('resume', 'is', null)
                .single();

            setResumeUploaded(!!resumeCheck);

            // 3. Check for LinkedIn Token (OAuth Return)
            const token = await getLinkedInToken();
            if (token) {
                setIsLinkedInConnected(true);
            }

        } catch (error) {
            console.error("Failed to load profile", error);
        } finally {
            setFetching(false);
        }
    };
    loadData();
  }, [user.id]);

  // --- LINKEDIN HANDLERS ---
  const handleConnectLinkedIn = async () => {
      try {
          await connectLinkedIn();
          // The page will redirect.
      } catch (error) {
          console.error("LinkedIn Connect Error:", error);
          alert("Failed to initiate LinkedIn connection.");
      }
  };

  const startLinkedInSync = () => {
      setShowPrivacyModal(true);
  };

  const confirmPrivacyAndSync = async () => {
      setShowPrivacyModal(false);
      setSyncingLinkedIn(true);
      try {
          const token = await getLinkedInToken();
          if (!token) throw new Error("No provider token found. Please reconnect.");

          // 1. Fetch Data (Simulated or Real)
          const rawData = await fetchLinkedInProfileData(token);

          // 2. Analyze with AI
          const aiResult = await analyzeLinkedInData(rawData, user.program);
          setLinkedInCandidate(aiResult);

          setSyncingLinkedIn(false);
          setShowLinkedInResultModal(true);
      } catch (error: any) {
          console.error("Sync Error:", error);
          setSyncingLinkedIn(false);
          alert("Sync Failed: " + (error.message || "Could not retrieve data."));
      }
  };

  const applyLinkedInUpdates = () => {
    if (!linkedInCandidate) return;

    // 1. Apply Past Employment
    if (linkedInCandidate.past_employment && linkedInCandidate.past_employment.length > 0) {
        setProfileData(prev => ({
            ...prev,
            employment: [
                ...linkedInCandidate.past_employment.map((job: any) => ({
                    ...job,
                    is_current_job: false
                })),
                ...prev.employment
            ]
        }));
    }

    // 2. Handle Current Job
    if (linkedInCandidate.current_job) {
        // Prepare it for the "Current Job Verification" modal logic which is robust
        setCurrentJobCandidate({
            employment_status: linkedInCandidate.current_job.employment_status,
            company_name: linkedInCandidate.current_job.company_name,
            current_position: linkedInCandidate.current_job.position,
            date_hired: linkedInCandidate.current_job.date_hired,
            industry: linkedInCandidate.current_job.industry,
            company_address: linkedInCandidate.current_job.company_address
        });

        // Trigger Job Analysis Modal to handle alignment check
        setAnalyzingJob(true); 
        // Re-analyze alignment specifically for the verification modal
        analyzeJobDetails(
            linkedInCandidate.current_job.position, 
            linkedInCandidate.current_job.company_name, 
            user.program, 
            linkedInCandidate.current_job.employment_status
        ).then(analysis => {
             setCurrentJobCandidate(prev => ({
                 ...prev,
                 job_alignment: analysis.job_alignment,
                 current_job_level: analysis.current_job_level,
                 industry: analysis.industry // Refresh industry
             }));
             setAnalyzingJob(false);
             setShowCurrentJobModal(true); // Open the robust modal
        });
    }

    setShowLinkedInResultModal(false);
    alert("Past employment history imported! Please review the Current Job details in the next window.");
  };

  // --- RESUME HANDLERS ---
  const handleResumeUpload = async (file: File) => {
    setParsing(true);
    setVerificationWarning(null);

    try {
        const userType = user.enrollment_status === 'Graduating' ? 'graduating' : 'alumni';

        await uploadResumeToDB(file, user.id!, userType);
        setResumeUploaded(true);

        const reader = new FileReader();
        reader.readAsDataURL(file);
        reader.onload = async () => {
            const base64Data = (reader.result as string).split(',')[1];
            try {
                const extracted = await parseResume(base64Data, file.type);

                // Name Mismatch Warning
                if (extracted.personal) {
                    const extractedLast = extracted.personal.last_name?.toLowerCase() || '';
                    const userLast = lastName.toLowerCase();
                    if (extractedLast && !extractedLast.includes(userLast)) {
                        setVerificationWarning(`Warning: The name on the resume (${extracted.personal.first_name} ${extracted.personal.last_name}) does not match your account name.`);
                    }
                    if (extracted.personal.address && !address) setAddress(extracted.personal.address);
                    if (extracted.personal.contact_no && !contactNo) setContactNo(extracted.personal.contact_no);
                    if (extracted.personal.email && !email) setEmail(extracted.personal.email);
                }

                // SPLIT EMPLOYMENT: Past vs Current
                const allEmployment = extracted.employment || [];
                const pastJobs: EmploymentHistory[] = [];
                let foundCurrentJob: Partial<EmploymentRecord> | null = null;

                allEmployment.forEach((job: any) => {
                    if (job.is_current_job) {
                        // Found a "Present" job
                        foundCurrentJob = {
                            employment_status: job.employment_status || 'Employed',
                            company_name: job.company_name,
                            business_name: job.business_name, // In case of self-employed
                            current_position: job.position,
                            date_hired: job.date_hired,
                            company_address: job.company_address || '', // Likely missing in resume
                            business_address: job.business_address || ''
                        };
                    } else {
                        pastJobs.push(job);
                    }
                });

                // Update Profile Data State (Past jobs + Other sections)
                setProfileData(prev => ({
                    ...prev,
                    education: { ...prev.education, ...extracted.education },
                    employment: [...(prev.employment || []), ...pastJobs],
                    community: [...(prev.community || []), ...(extracted.community || [])],
                    attributes: { ...prev.attributes, ...extracted.attributes } // Auto-fill Attributes
                }));

                // Handle Current Job Process
                if (foundCurrentJob) {
                    setAnalyzingJob(true);
                    setCurrentJobCandidate(foundCurrentJob);
                    setShowCurrentJobModal(true);

                    // Run AI Analysis for the Current Job (Industry & Alignment)
                    try {
                        // @ts-ignore
                        const jobTitle = foundCurrentJob.current_position || foundCurrentJob.business_name || 'Employee';
                        // @ts-ignore
                        const company = foundCurrentJob.company_name || foundCurrentJob.business_name || 'Company';
                        // @ts-ignore
                        const type = foundCurrentJob.employment_status === 'Self-employed' ? 'Self-employed' : 'Employed';

                        const analysis = await analyzeJobDetails(jobTitle, company, program, type);

                        setCurrentJobCandidate(prev => ({
                            ...prev,
                            industry: analysis.industry,
                            job_alignment: analysis.job_alignment,
